SELECT Patents_info, cpc, publication_date, grant_date FROM publicationinfo WHERE grant_date IS NOT NULL AND (
  COALESCE(
    TRY_STRPTIME(grant_date, '%Y-%m-%d %H:%M:%S'),
    TRY_STRPTIME(grant_date, '%B %d, %Y at %I:%M %p'),
    TRY_STRPTIME(grant_date, '%d %B %Y, %H:%M'),
    TRY_STRPTIME(grant_date, '%d %b %Y, %H:%M'),
    TRY_STRPTIME(grant_date, '%B %d, %Y at %H:%M'),
    TRY_STRPTIME(grant_date, '%m/%d/%Y %H:%M:%S')
  ) BETWEEN DATE('2019-07-01') AND DATE('2019-12-31')
) AND (Patents_info LIKE '%Germany%' OR Patents_info LIKE '%DE%') LIMIT 1;
